prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mf ?srcRef ?tgtRef ?msgRef ?srcType ?tgtType WHERE {
  ?mf a bboExt:MessageFlow .
  ?mf tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_7e6c8e81_8977_4cbd_818d_dec74bfc816b> .
  ?mf bboExt:sourceRef ?srcRef .
  ?mf bboExt:targetRef ?tgtRef .
  OPTIONAL { ?mf bboExt:messageRef ?msgRef . }
  OPTIONAL {
    ?srcElem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_7e6c8e81_8977_4cbd_818d_dec74bfc816b> .
    FILTER(STRENDS(STR(?srcElem), ?srcRef))
    ?srcElem a ?srcType .
  }
  OPTIONAL {
    ?tgtElem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_7e6c8e81_8977_4cbd_818d_dec74bfc816b> .
    FILTER(STRENDS(STR(?tgtElem), ?tgtRef))
    ?tgtElem a ?tgtType .
  }
}
LIMIT 25
